typedef struct _WER_REPORT_INFORMATION {
DWORD  dwSize;   HANDLE hProcess;
WCHAR  wzConsentKey[64];
WCHAR  wzFriendlyEventName[128];   WCHAR  wzApplicationName[128];
WCHAR  wzApplicationPath[MAX_PATH];
WCHAR  wzDescription[512];   HWND   hwndParent;
} WER_REPORT_INFORMATION, *PWER_REPORT_INFORMATION;
成员 dwSize
此结构的大小（以字节为单位）。 hProcess
正在为其生成报表的进程句柄。 如果此成员为 NULL，则这是调用进程。 wzConsentKey[64]
用于查找同意设置的名称。 如果此成员为空，则默认值为 WerReportCreate 的
pwzEventType 参数指定的名称。 wzFriendlyEventName[128]
显示名称。 如果此成员为空，则默认值为 WerReportCreate 的 pwzEventType 参数指定的名称。
wzApplicationName[128]
应用程序的名称。 如果此参数为空，则默认值为映像文件的基名称。 wzApplicationPath[MAX_PATH]
应用程序的完整路径。 wzDescription[512]
问题的说明。 此说明显示在 Windows Vista 上 的问题报告和解决方案 或 Windows 7 上
的操作中心 的问题报告窗格中。 hwndParent
父窗口的句柄。

